/* eslint-disable */
import { Document, Packer, Paragraph, TextRun, HeadingLevel, Table, TableRow, TableCell, WidthType, LevelFormat } from 'docx';

export async function generateWordDocument(documentData = {}, procedureData = []) {
    const formattedDate = formatDate(documentData.headerConfig?.fecha);
    const doc = new Document({
        styles: {
            paragraphStyles: [
                { id: "Heading1", name: "Heading 1", basedOn: "Normal", next: "Normal", quickFormat: true },
            ],
        },
        numbering: {
            config: [
                {
                    reference: "bullet-numbering",
                    levels: [
                        { level: 0, format: LevelFormat.BULLET, text: "•", alignment: "left", style: { run: { bold: false } } },
                    ],
                },
                {
                    reference: "decimal-numbering",
                    levels: [
                        { level: 0, format: LevelFormat.DECIMAL, text: "%1.", alignment: "left" },
                    ],
                },
                {
                    reference: "letter-numbering",
                    levels: [
                        { level: 0, format: LevelFormat.LOWER_LETTER, text: "%1.", alignment: "left" },
                    ],
                },
            ],
        },
    });

    const children = [];

    // Header table / info simplified as paragraphs
    children.push(
        new Paragraph({ text: documentData.headerConfig?.policyName || 'PROCEDIMIENTO', heading: HeadingLevel.HEADING_1 }),
        new Paragraph({ text: `Código: ${documentData.headerConfig?.codigo || 'XX-P-XXX-#'}` }),
        new Paragraph({ text: `Área: ${documentData.headerConfig?.area || 'Área responsable'}` }),
        new Paragraph({ text: `Unidad: ${documentData.headerConfig?.unidad || 'Unidad específica'}` }),
        new Paragraph({ text: `Revisión: ${documentData.headerConfig?.revision || '(1)'}` }),
        new Paragraph({ text: `Fecha: ${formattedDate}` })
    );

    // Sections
    children.push(new Paragraph({ text: '1. Objetivo o Propósito', heading: HeadingLevel.HEADING_1 }));
    children.push(...parseHtmlToParagraphs(documentData.objetivo));

    children.push(new Paragraph({ text: '2. Alcance', heading: HeadingLevel.HEADING_1 }));
    children.push(...parseHtmlToParagraphs(documentData.alcance));

    children.push(new Paragraph({ text: '3. Responsabilidades', heading: HeadingLevel.HEADING_1 }));
    children.push(...parseHtmlToParagraphs(documentData.responsabilidades));

    children.push(new Paragraph({ text: '4. Normativa', heading: HeadingLevel.HEADING_1 }));
    children.push(...parseHtmlToParagraphs(documentData.normativa));

    // Procedimiento (tabla)
    children.push(new Paragraph({ text: '5. Procedimiento', heading: HeadingLevel.HEADING_1 }));
    children.push(createProcedureTable(procedureData));

    children.push(new Paragraph({ text: '6. Anexos', heading: HeadingLevel.HEADING_1 }));
    children.push(...parseHtmlToParagraphs(documentData.anexos));

    children.push(new Paragraph({ text: '7. Términos y Referencias', heading: HeadingLevel.HEADING_1 }));
    children.push(...parseHtmlToParagraphs(documentData.terminos));

    doc.addSection({ children });

    // Generar blob y descargar
    try {
        const blob = await Packer.toBlob(doc);
        const fileName = `${documentData.headerConfig?.policyName || 'Procedimiento'}.docx`;
        if (window.navigator && window.navigator.msSaveOrOpenBlob) {
            window.navigator.msSaveOrOpenBlob(blob, fileName);
        } else {
            const url = URL.createObjectURL(blob);
            const a = document.createElement('a');
            a.href = url;
            a.download = fileName;
            a.style.display = 'none';
            document.body.appendChild(a);
            a.click();
            setTimeout(() => {
                document.body.removeChild(a);
                URL.revokeObjectURL(url);
            }, 150);
        }
        return true;
    } catch (err) {
        throw err;
    }
}

// Helpers

function formatDate(dateInput) {
    const d = dateInput ? new Date(dateInput) : new Date();
    const day = String(d.getDate()).padStart(2, '0');
    const month = String(d.getMonth() + 1).padStart(2, '0');
    const year = d.getFullYear();
    return `${day}-${month}-${year}`;
}

function safeText(value) {
    if (value == null) return '';
    return String(value).replace(/\s+/g, ' ').trim();
}

// Convierte HTML simple (p, ul, ol, li, br) en Paragraphs compatibles con docx.
// Usa parser DOM en navegador; si falla usa fallback por regex.
function parseHtmlToParagraphs(html = '') {
    const paragraphs = [];
    if (!html) return paragraphs;
    try {
        const parser = new DOMParser();
        const doc = parser.parseFromString(`<div>${html}</div>`, 'text/html');
        const root = doc.body.firstElementChild || doc.body;
        root.childNodes.forEach(node => {
            if (node.nodeType !== Node.ELEMENT_NODE) return;
            const tag = node.tagName.toLowerCase();
            if (tag === 'p') {
                const text = safeText(node.textContent);
                if (text) paragraphs.push(new Paragraph({ children: [new TextRun(text)] }));
            } else if (tag === 'ul' || tag === 'ol') {
                const isOrdered = tag === 'ol';
                const isLetter = node.getAttribute && /data-type\s*=\s*["']letter["']/i.test(node.outerHTML);
                const numRef = isLetter ? 'letter-numbering' : (isOrdered ? 'decimal-numbering' : 'bullet-numbering');
                node.querySelectorAll('li').forEach(li => {
                    const liText = safeText(li.textContent);
                    if (!liText) return;
                    paragraphs.push(new Paragraph({
                        children: [new TextRun(liText)],
                        numbering: { reference: numRef, level: 0 },
                    }));
                });
            } else {
                // otros tags: tratar su texto como párrafo
                const text = safeText(node.textContent);
                if (text) paragraphs.push(new Paragraph({ children: [new TextRun(text)] }));
            }
        });
    } catch (e) {
        // Fallback simple: quitar tags y devolver como párrafos por saltos de línea
        const cleaned = String(html).replace(/<br\s*\/?>/gi, '\n').replace(/<[^>]+>/g, '');
        cleaned.split(/\n+/).map(s => safeText(s)).filter(Boolean).forEach(t => {
            paragraphs.push(new Paragraph({ children: [new TextRun(t)] }));
        });
    }
    return paragraphs;
}

function createProcedureTable(data = []) {
    // Cabecera
    const headerRow = new TableRow({
        children: [
            new TableCell({ width: { size: 1700, type: WidthType.DXA }, children: [new Paragraph({ children: [new TextRun({ text: '(#)', bold: true })] })] }),
            new TableCell({ width: { size: 2800, type: WidthType.DXA }, children: [new Paragraph({ children: [new TextRun({ text: '(Quien)', bold: true })] })] }),
            new TableCell({ width: { size: 6800, type: WidthType.DXA }, children: [new Paragraph({ children: [new TextRun({ text: '(Actividad)', bold: true })] })] }),
        ],
    });

    const rows = [headerRow];

    data.forEach(row => {
        let number = safeText(row.number || '');
        if (number) {
            if (!number.includes('.') && !isNaN(number)) number = `5.${number}`;
            else if (!number.startsWith('5.')) {
                const segs = number.split('.');
                if (segs.every(s => /^\d+$/.test(s.trim()))) number = `5.${number}`;
            }
        }
        const who = safeText(row.who || '');
        const activity = safeText((row.activity || '').replace(/<[^>]*>/g, ''));

        rows.push(new TableRow({
            children: [
                new TableCell({ children: [new Paragraph({ children: [new TextRun(number)] })] }),
                new TableCell({ children: [new Paragraph({ children: [new TextRun(who)] })] }),
                new TableCell({ children: [new Paragraph({ children: [new TextRun(activity)] })] }),
            ],
        }));
    });

    return new Table({
        rows,
        width: { size: 100, type: WidthType.PERCENTAGE },
    });
}
